const listEnabledModels = `-- name: ListEnabledModels :many
SELECT m.id, m.model_id, m.name, m.provider_id, m.type, m.enable, m.config, m.created_at, m.updated_at, m.team_id
FROM models m
JOIN providers p ON m.provider_id = p.id
WHERE p.enable = true
  AND m.enable = true
  AND m.type NOT IN ('speech', 'transcription', 'video')
ORDER BY m.created_at DESC
`

func (q *Queries) ListEnabledModels(ctx context.Context) ([]Model, error) {
	rows, err := q.db.Query(ctx, listEnabledModels)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []Model
	for rows.Next() {
		var i Model
		if err := rows.Scan(
			&i.ID,
			&i.ModelID,
			&i.Name,
			&i.ProviderID,
			&i.Type,
			&i.Enable,
			&i.Config,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.TeamID,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

